## 📝 实施计划

### 阶段 1: 扩展配置验证器 (45 分钟)

**文件**: `src/config/validator.ts`

```typescript
// ==================== 配置缓存管理 ====================

let cachedConfig: AppConfig | null = null;
let configLoadTime: Date | null = null;
let configVersion: number = 0;

/**
 * 清除配置缓存
 */
export function invalidateCache(): void {
  cachedConfig = null;
  configLoadTime = null;
  configVersion++;
  console.log('🔄 配置缓存已清除');
}

/**
 * 重新加载配置
 */
export function reloadConfig(): AppConfig {
  console.log('🔄 正在重新加载配置...');
  invalidateCache();
  const newConfig = getConfig();

  // 验证配置加载成功
  if (!newConfig) {
    throw new Error('配置重新加载失败');
  }

  console.log('✅ 配置重新加载成功');
  return newConfig;
}

/**
 * 获取配置元信息
 */
export function getConfigMetadata() {
  return {
    version: configVersion,
    loadTime: configLoadTime,
    cached: !!cachedConfig,
  };
}

/**
 * 获取脱敏后的配置（用于 API 返回）
 */
export function getSafeConfig(): Omit<AppConfig, 'api'> & { 
  api: Omit<ApiConfig, 'anthropicAuthToken'> 
} {
  const config = getConfig();

  return {
    ...config,
    api: {
      ...config.api,
      anthropicAuthToken: config.api.anthropicAuthToken 
        ? '***' + config.api.anthropicAuthToken.slice(-4)
        : undefined,
    },
  };
}
```

