### 阶段 2: 添加配置 API 路由 (30 分钟)

**新文件**: `src/dashboard/routes/config.ts`

```typescript
import { FastifyInstance } from 'fastify';
import {
  reloadConfig,
  getSafeConfig,
  getConfigMetadata,
  validateAllConfig
} from '../../config/validator';

export async function registerConfigRoutes(fastify: FastifyInstance) {

  // 获取当前配置（脱敏）
  fastify.get('/config', async (request, reply) => {
    const config = getSafeConfig();
    const metadata = getConfigMetadata();

    return reply.send({
      success: true,
      data: {
        config,
        metadata,
      },
    });
  });

  // 重新加载配置
  fastify.post('/config/reload', async (request, reply) => {
    try {
      const oldConfig = getSafeConfig();
      const oldMetadata = getConfigMetadata();

      // 重新加载
      const newConfig = reloadConfig();
      const newMetadata = getConfigMetadata();

      return reply.send({
        success: true,
        message: '配置重新加载成功',
        data: {
          oldVersion: oldMetadata.version,
          newVersion: newMetadata.version,
          changes: compareConfig(oldConfig, newConfig),
          timestamp: new Date(),
        },
      });
    } catch (error: any) {
      return reply.code(400).send({
        success: false,
        error: {
          message: error.message,
          code: 'CONFIG_RELOAD_FAILED',
        },
      });
    }
  });

  // 验证配置（不应用）
  fastify.post('/config/validate', async (request, reply) => {
    try {
      // 临时加载并验证配置
      const tempConfig = validateAllConfig();

      return reply.send({
        success: true,
        message: '配置验证通过',
        data: {
          valid: true,
          timestamp: new Date(),
        },
      });
    } catch (error: any) {
      return reply.code(400).send({
        success: false,
        error: {
          message: error.message,
          code: 'CONFIG_VALIDATION_FAILED',
        },
      });
    }
  });
}

/**
 * 比较两个配置的差异
 */
function compareConfig(oldConfig: any, newConfig: any) {
  const changes: string[] = [];

  // 比较各个配置项
  if (oldConfig.dashboard.port !== newConfig.dashboard?.port) {
    changes.push(`dashboard.port: ${oldConfig.dashboard.port} → ${newConfig.dashboard?.port}`);
  }

  if (oldConfig.dashboard.logLevel !== newConfig.dashboard?.logLevel) {
    changes.push(`dashboard.logLevel: ${oldConfig.dashboard.logLevel} → ${newConfig.dashboard?.logLevel}`);
  }

  if (oldConfig.iteration.intervalMs !== newConfig.iteration?.intervalMs) {
    changes.push(`iteration.intervalMs: ${oldConfig.iteration.intervalMs} → ${newConfig.iteration?.intervalMs}`);
  }

  return changes;
}
```

