### 阶段 4: 文件监听（可选增强）(30 分钟)

**新文件**: `src/config/watcher.ts`

```typescript
import chokidar from 'chokidar';
import path from 'path';
import { invalidateCache } from './validator';

let watcher: chokidar.FSWatcher | null = null;

export function startConfigWatcher(callback?: (event: string) => void) {
  const envPath = path.join(process.cwd(), '.env');

  watcher = chokidar.watch(envPath, {
    persistent: true,
    ignoreInitial: true,
  });

  watcher.on('change', () => {
    console.log('📝 检测到 .env 文件变化，重新加载配置...');
    invalidateCache();

    if (callback) {
      callback('config.changed');
    }
  });

  console.log('👀 配置文件监听已启动');
}

export function stopConfigWatcher() {
  if (watcher) {
    watcher.close();
    watcher = null;
    console.log('🛑 配置文件监听已停止');
  }
}
```

